        fun addPEAKDECELERATIONEPOCH(builder: FlatBufferBuilder, peakDecelerationEpoch: Int) = builder.addOffset(28, peakDecelerationEpoch, 0)
        fun addPEAKDECELERATIONG(builder: FlatBufferBuilder, peakDecelerationG: Double) = builder.addDouble(29, peakDecelerationG, 0.0)
        fun addBREAKUPEPOCH(builder: FlatBufferBuilder, breakupEpoch: Int) = builder.addOffset(30, breakupEpoch, 0)
        fun addBREAKUPALTITUDEM(builder: FlatBufferBuilder, breakupAltitudeM: Double) = builder.addDouble(31, breakupAltitudeM, 0.0)
        fun addIMPACTEPOCH(builder: FlatBufferBuilder, impactEpoch: Int) = builder.addOffset(32, impactEpoch, 0)
        fun addIMPACTLATITUDEDEG(builder: FlatBufferBuilder, impactLatitudeDeg: Double) = builder.addDouble(33, impactLatitudeDeg, 0.0)
        fun addIMPACTLONGITUDEDEG(builder: FlatBufferBuilder, impactLongitudeDeg: Double) = builder.addDouble(34, impactLongitudeDeg, 0.0)
        fun addALONGTRACKUNCERTAINTYM(builder: FlatBufferBuilder, alongTrackUncertaintyM: Double) = builder.addDouble(35, alongTrackUncertaintyM, 0.0)
        fun addCROSSTRACKUNCERTAINTYM(builder: FlatBufferBuilder, crossTrackUncertaintyM: Double) = builder.addDouble(36, crossTrackUncertaintyM, 0.0)
        fun addSURVIVINGMASSKG(builder: FlatBufferBuilder, survivingMassKg: Double) = builder.addDouble(37, survivingMassKg, 0.0)
        fun addSURVIVINGFRAGMENTCOUNT(builder: FlatBufferBuilder, survivingFragmentCount: UInt) = builder.addInt(38, survivingFragmentCount.toInt(), 0)
        fun addSURVIVALPROBABILITY(builder: FlatBufferBuilder, survivalProbability: Double) = builder.addDouble(39, survivalProbability, 0.0)
        fun addCASUALTYEXPECTATION(builder: FlatBufferBuilder, casualtyExpectation: Double) = builder.addDouble(40, casualtyExpectation, 0.0)
        fun addGROUNDRISKPROBABILITY(builder: FlatBufferBuilder, groundRiskProbability: Double) = builder.addDouble(41, groundRiskProbability, 0.0)
        fun addMINTHERMALMARGIN(builder: FlatBufferBuilder, minThermalMargin: Double) = builder.addDouble(42, minThermalMargin, 0.0)
        fun addMINSTRUCTURALMARGIN(builder: FlatBufferBuilder, minStructuralMargin: Double) = builder.addDouble(43, minStructuralMargin, 0.0)
        fun addFRAGMENTS(builder: FlatBufferBuilder, fragments: Int) = builder.addOffset(44, fragments, 0)
        fun createFragmentsVector(builder: FlatBufferBuilder, data: IntArray) : Int {
            builder.startVector(4, data.size, 4)
            for (i in data.size - 1 downTo 0) {
                builder.addOffset(data[i])
            }
            return builder.endVector()
        }
        fun startFragmentsVector(builder: FlatBufferBuilder, numElems: Int) = builder.startVector(4, numElems, 4)
        fun addASSUMPTIONS(builder: FlatBufferBuilder, assumptions: Int) = builder.addOffset(45, assumptions, 0)
        fun createAssumptionsVector(builder: FlatBufferBuilder, data: IntArray) : Int {
            builder.startVector(4, data.size, 4)
            for (i in data.size - 1 downTo 0) {
                builder.addOffset(data[i])
            }
            return builder.endVector()
        }
        fun startAssumptionsVector(builder: FlatBufferBuilder, numElems: Int) = builder.startVector(4, numElems, 4)
        fun addCOMMENT(builder: FlatBufferBuilder, comment: Int) = builder.addOffset(46, comment, 0)
        fun endREM(builder: FlatBufferBuilder) : Int {
            val o = builder.endTable()
            return o
        }
        fun finishREMBuffer(builder: FlatBufferBuilder, offset: Int) = builder.finish(offset, "$REM")
        fun finishSizePrefixedREMBuffer(builder: FlatBufferBuilder, offset: Int) = builder.finishSizePrefixed(offset, "$REM")
    }
